const raw = ($input.first().json.mensaje || '').toString();
let msg = raw.substring(0, 800).replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '');
const patterns = [/ignora (todas?|las?)? ?(instrucciones?|reglas?|todo)/gi,/olvida (todo|las instrucciones)/gi,/act[úu]a como/gi,/eres ahora/gi,/nuevo (rol|personaje|modo)/gi,/muéstrame (tu|el) (prompt|system|instrucciones)/gi,/\[SYSTEM\]/gi,/jailbreak/gi,/DAN mode/gi];
let injection_detected = false;
for (const p of patterns) { if (p.test(msg)) { injection_detected = true; msg = msg.replace(p,'[filtrado]'); } }
return { mensaje: msg, injection_detected };

const raw = $input.first().json.text;
const clean = raw.replace(/```json/g,'').replace(/```/g,'').trim();
let parsed;
try { parsed = JSON.parse(clean); } catch(e) { parsed = {intent:"other",lang:"es",reason:"parse error"}; }
if (!parsed.intent) parsed.intent = "other";
if (!parsed.lang)   parsed.lang   = "es";
return { json: parsed };

const detected = $('Edit Fields2').item.json.lang || 'es';
const intent   = $('Edit Fields2').item.json.intent;
let cfg = {};
try { const r = $('Leer Config Sesión').item.json.session_config; if(r) cfg = JSON.parse(r); } catch(e){}
const stored_lang    = cfg.lang || 'es';
const lang_confirmed = cfg.lang_confirmed || false;
const expired        = (Math.floor(Date.now()/1000) - (cfg.last_activity||0)) > 1800;
let session_lang = (expired && !lang_confirmed) ? 'es' : stored_lang;
const needs_confirm  = detected !== 'es' && detected !== session_lang && !lang_confirmed;
return { session_lang, detected_lang: detected, needs_lang_confirm: needs_confirm, intent,
         new_config: JSON.stringify({ lang: session_lang, lang_confirmed, last_activity: Math.floor(Date.now()/1000) }) };

const intent = $('Edit Fields2').item.json.intent;
const phone_number_id = $('Edit Fields1').item.json.phone_number_id;
const recipient = $('WhatsApp Trigger').item.json.messages[0].from;
const lang = $('Gestionar Idioma').item.json.session_lang || 'es';
// ⚠️ Reemplaza con los IDs reales tras publicar en Meta
const FLOW_IDS = { agendar:'TU_FLOW_ID_AGENDAR', consultar_cita:'TU_FLOW_ID_CONSULTAR', cancelar_cita:'TU_FLOW_ID_CANCELAR', afiliacion:'TU_FLOW_ID_AFILIACION' };
const CFG = {
  es:{ agendar:{h:'📅 Agendar Cita',b:'Verificamos tu identidad para agendar. Solo toma un minuto.',cta:'Agendar →',s:'VALIDAR_IDENTIDAD'}, consultar_cita:{h:'🔍 Consultar Cita',b:'Verificamos tu identidad para mostrarte tus citas.',cta:'Ver citas →',s:'VALIDAR_IDENTIDAD'}, cancelar_cita:{h:'❌ Cancelar Cita',b:'Verificamos tu identidad para cancelar tu cita.',cta:'Cancelar →',s:'VALIDAR_IDENTIDAD'}, afiliacion:{h:'📋 Afiliación',b:'Iniciemos tu proceso de afiliación a Sersocial IPS.',cta:'Iniciar →',s:'SELECCIONAR_REGIMEN'} },
  en:{ agendar:{h:'📅 Book Appointment',b:"We'll verify your identity to book your appointment.",cta:'Book →',s:'VALIDAR_IDENTIDAD'}, consultar_cita:{h:'🔍 My Appointments',b:"We'll verify your identity to show your appointments.",cta:'View →',s:'VALIDAR_IDENTIDAD'}, cancelar_cita:{h:'❌ Cancel Appointment',b:"We'll verify your identity to cancel.",cta:'Cancel →',s:'VALIDAR_IDENTIDAD'}, afiliacion:{h:'📋 Enrollment',b:"Let's start your enrollment at Sersocial IPS.",cta:'Start →',s:'SELECCIONAR_REGIMEN'} }
};
const c = (CFG[lang]||CFG['es'])[intent];
if(!c) throw new Error(`Intent no mapeado: ${intent}`);
const payload = { messaging_product:'whatsapp', recipient_type:'individual', to:recipient, type:'interactive',
  interactive:{ type:'flow', header:{type:'text',text:c.h}, body:{text:c.b}, footer:{text:'Fundación Sersocial IPS'},
    action:{ name:'flow', parameters:{ flow_message_version:'3', flow_token:`${recipient}_${Date.now()}`, flow_id:FLOW_IDS[intent], flow_cta:c.cta, flow_action:'navigate', flow_action_payload:{screen:c.s} } } } };
return { payload:JSON.stringify(payload), phone_number_id, recipient, intent };

