const msg = $('WhatsApp Trigger').item.json.messages[0];
const nfm = (msg.interactive||{}).nfm_reply||{};
let flow_data={};
try{ flow_data=JSON.parse(nfm.response_json||'{}'); }catch(e){}
const map={agendar_cita:'agendar',consultar_cita:'consultar_cita',cancelar_cita:'cancelar_cita',afiliacion:'afiliacion'};
return { flow_name:nfm.name||'unknown', flow_intent:map[nfm.name]||'unknown', flow_data, telefono:msg.from };
